document.addEventListener("click",function(n){if(!n.target.closest("#cookie-banner-link"))return;if(n.preventDefault(),"function"==typeof window.openCookieConsentManager){window.openCookieConsentManager();return}let e=document.querySelector("[data-acris-cookie-consent]");if(!e){console.warn("Acris cookie consent is not enabled on this sales channel.");return}let o=window.PluginManager.getPluginInstanceFromElement(e,"AcrisCookieConsent");o?.openOffCanvas?.()});